const express = require('express');
const morgan = require('morgan');
const winston = require('winston');

// Define sensitive patterns to redact
const SENSITIVE_PATTERNS = [
  /authorization/i,
  /x-api-key/i,
  /api[_-]?key/i,
  /secret/i,
  /token/i,
  /password/i,
  /bearer/i,
  /aws[_-]?access[_-]?key/i,
  /aws[_-]?secret/i
];

// Redaction function
function redactSensitiveData(obj, parentKey = '') {
  if (!obj || typeof obj !== 'object') return obj;

  if (Array.isArray(obj)) {
    return obj.map((item, index) => redactSensitiveData(item, `${parentKey}[${index}]`));
  }

  const redacted = {};
  for (const [key, value] of Object.entries(obj)) {
    const fullKey = parentKey ? `${parentKey}.${key}` : key;

    // Check if key matches sensitive pattern
    const isSensitive = SENSITIVE_PATTERNS.some(pattern => pattern.test(key));

    if (isSensitive) {
      // Redact but show first 4 chars for debugging
      redacted[key] = typeof value === 'string' && value.length > 8
        ? `${value.substring(0, 4)}...***REDACTED***`
        : '***REDACTED***';
    } else if (typeof value === 'object' && value !== null) {
      redacted[key] = redactSensitiveData(value, fullKey);
    } else {
      redacted[key] = value;
    }
  }

  return redacted;
}

// Middleware to sanitize request data before logging
function sanitizeLoggingMiddleware(req, res, next) {
  // Store original headers and body
  const originalHeaders = req.headers;
  const originalBody = req.body;

  // Create sanitized versions
  req.sanitizedHeaders = redactSensitiveData(originalHeaders);
  req.sanitizedBody = redactSensitiveData(originalBody);

  // Override res.json to sanitize response
  const originalJson = res.json.bind(res);
  res.json = function(body) {
    res.sanitizedResponseBody = redactSensitiveData(body);
    return originalJson(body);
  };

  next();
}

// Configure Winston logger with sanitization
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  transports: [
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      )
    }),
    new winston.transports.File({ 
      filename: 'logs/app.log',
      maxsize: 10485760, // 10MB
      maxFiles: 5
    })
  ]
});

// Custom Morgan token for sanitized logging
morgan.token('sanitized-headers', (req) => {
  return JSON.stringify(req.sanitizedHeaders || {});
});

const app = express();
app.use(express.json());

// Apply sanitization middleware BEFORE logging
app.use(sanitizeLoggingMiddleware);

// Use Morgan with sanitized tokens
app.use(morgan(':method :url :status :sanitized-headers', {
  stream: {
    write: (message) => logger.info(message.trim())
  }
}));

// Example endpoint
app.post('/api/users', (req, res) => {
  // Log with sanitized data
  logger.info('User creation request', {
    headers: req.sanitizedHeaders,
    body: req.sanitizedBody,
    ip: req.ip
  });

  res.json({ success: true, userId: '12345' });
});

// Error handler with sanitization
app.use((err, req, res, next) => {
  logger.error('Application error', {
    error: err.message,
    stack: err.stack,
    headers: req.sanitizedHeaders,
    url: req.url,
    method: req.method
  });

  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000, () => {
  logger.info('Server started on port 3000');
});

const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');

// Initialize Secrets Manager client
const secretsClient = new SecretsManagerClient({ 
  region: process.env.AWS_REGION || 'us-east-1'
});

// In-memory cache for secrets (Lambda container reuse)
const secretsCache = new Map();
const CACHE_TTL = 300000; // 5 minutes in milliseconds

/**
 * Retrieve secret from AWS Secrets Manager with caching
 * @param {string} secretName - Name or ARN of the secret
 * @returns {Promise<object>} - Parsed secret value
 */
async function getSecret(secretName) {
  const now = Date.now();
  const cached = secretsCache.get(secretName);

  // Return cached secret if still valid
  if (cached && (now - cached.timestamp) < CACHE_TTL) {
    console.log(`Using cached secret: ${secretName}`);
    return cached.value;
  }

  try {
    console.log(`Fetching secret from Secrets Manager: ${secretName}`);
    const command = new GetSecretValueCommand({ SecretId: secretName });
    const response = await secretsClient.send(command);

    let secretValue;
    if (response.SecretString) {
      secretValue = JSON.parse(response.SecretString);
    } else {
      // Binary secret (base64 decode if needed)
      const buff = Buffer.from(response.SecretBinary, 'base64');
      secretValue = buff.toString('ascii');
    }

    // Cache the secret
    secretsCache.set(secretName, {
      value: secretValue,
      timestamp: now
    });

    return secretValue;
  } catch (error) {
    console.error(`Error retrieving secret ${secretName}:`, {
      errorType: error.name,
      // DO NOT log error.message as it may contain secret data
      requestId: error.$metadata?.requestId
    });
    throw new Error('Failed to retrieve credentials');
  }
}

/**
 * Lambda handler with secure secret management
 */
exports.handler = async (event, context) => {
  console.log('Lambda invoked', {
    requestId: context.requestId,
    functionVersion: context.functionVersion,
    // NEVER log the event object directly - it may contain API keys
    eventType: event.httpMethod || 'unknown'
  });

  try {
    // Retrieve secrets from Secrets Manager
    const apiCredentials = await getSecret('prod/external-api/credentials');

    // Use credentials for API call
    const response = await fetch('https://api.example.com/data', {
      headers: {
        'Authorization': `Bearer ${apiCredentials.apiKey}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      // Log error WITHOUT exposing credentials
      console.error('External API call failed', {
        statusCode: response.status,
        statusText: response.statusText,
        // DO NOT log response body or headers
        url: response.url
      });
      throw new Error('External API error');
    }

    const data = await response.json();

    // Log success (sanitized)
    console.log('API call successful', {
      recordCount: data.length || 0,
      requestId: context.requestId
    });

    return {
      statusCode: 200,
      headers: {
        'Content-Type': 'application/json',
        'X-Request-Id': context.requestId
      },
      body: JSON.stringify({
        success: true,
        data: data
      })
    };

  } catch (error) {
    console.error('Lambda execution error', {
      errorType: error.constructor.name,
      // Only log safe error properties
      message: error.message.replace(/sk-[a-zA-Z0-9]{20,}/g, '***REDACTED***'),
      requestId: context.requestId
    });

    return {
      statusCode: 500,
      body: JSON.stringify({
        error: 'Internal server error',
        requestId: context.requestId
      })
    };
  }
};

