# Terraform configuration for CloudWatch Logs protection

# 1. Create CloudWatch Logs data protection policy
resource "aws_cloudwatch_log_data_protection_policy" "api_keys" {
  log_group_name = aws_cloudwatch_log_group.lambda_logs.name

  policy_document = jsonencode({
    Name    = "APIKeyProtection"
    Version = "2021-06-01"

    Statement = [
      {
        Sid            = "DetectAndMaskAPIKeys"
        DataIdentifier = [
          # AWS credentials
          "arn:aws:dataprotection::aws:data-identifier/AwsSecretKey",
          "arn:aws:dataprotection::aws:data-identifier/AwsAccessKey",

          # Generic API keys and tokens
          "arn:aws:dataprotection::aws:data-identifier/ApiKey",
          "arn:aws:dataprotection::aws:data-identifier/AuthorizationToken",

          # Specific service patterns
          "arn:aws:dataprotection::aws:data-identifier/StripeApiKey",
          "arn:aws:dataprotection::aws:data-identifier/OpenAiApiKey",
          "arn:aws:dataprotection::aws:data-identifier/SlackWebhook"
        ]

        Operation = {
          Mask = {
            MaskConfig = {
              MaskType = "REDACT"
            }
          }
        }
      },
      {
        Sid            = "AuditSensitiveDataAccess"
        DataIdentifier = [
          "arn:aws:dataprotection::aws:data-identifier/EmailAddress",
          "arn:aws:dataprotection::aws:data-identifier/CreditCardNumber"
        ]

        Operation = {
          Audit = {
            FindingsDestination = {
              CloudWatchLogs = {
                LogGroup = aws_cloudwatch_log_group.security_findings.name
              }
              S3 = {
                Bucket = aws_s3_bucket.audit_logs.id
              }
            }
          }
        }
      }
    ]
  })
}

# 2. Create log group with appropriate retention
resource "aws_cloudwatch_log_group" "lambda_logs" {
  name              = "/aws/lambda/my-api-function"
  retention_in_days = 7  # Minimize retention for compliance
  kms_key_id        = aws_kms_key.logs.arn

  tags = {
    Environment = "production"
    Compliance  = "PCI-DSS"
  }
}

# 3. Create subscription filter to detect API keys
resource "aws_cloudwatch_log_subscription_filter" "api_key_detector" {
  name            = "api-key-detection"
  log_group_name  = aws_cloudwatch_log_group.lambda_logs.name
  filter_pattern  = "[time, request_id, level, msg=*api*key* || msg=*bearer* || msg=*authorization*]"
  destination_arn = aws_lambda_function.security_alert.arn

  depends_on = [aws_lambda_permission.allow_cloudwatch]
}

# 4. Lambda function for security alerts
resource "aws_lambda_function" "security_alert" {
  filename         = "security_alert.zip"
  function_name    = "cloudwatch-api-key-alert"
  role            = aws_iam_role.security_alert.arn
  handler         = "index.handler"
  runtime         = "nodejs18.x"
  timeout         = 30

  environment {
    variables = {
      SNS_TOPIC_ARN = aws_sns_topic.security_alerts.arn
      SLACK_WEBHOOK_SECRET = "prod/security/slack-webhook"  # Secrets Manager reference
    }
  }
}

