# 6. CloudWatch Metric Filter for monitoring
resource "aws_cloudwatch_log_metric_filter" "api_key_exposure" {
  name           = "APIKeyExposureCount"
  log_group_name = aws_cloudwatch_log_group.lambda_logs.name
  pattern        = "[time, request_id, level, msg=*api*key* || msg=*bearer*]"

  metric_transformation {
    name      = "APIKeyExposureEvents"
    namespace = "Security/Logs"
    value     = "1"
    unit      = "Count"
  }
}

# 7. CloudWatch Alarm for metric
resource "aws_cloudwatch_metric_alarm" "api_key_exposure_alarm" {
  alarm_name          = "api-key-exposure-detected"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = aws_cloudwatch_log_metric_filter.api_key_exposure.metric_transformation[0].name
  namespace           = "Security/Logs"
  period              = "60"
  statistic           = "Sum"
  threshold           = "0"
  alarm_description   = "Triggers when API keys are detected in CloudWatch Logs"
  alarm_actions       = [aws_sns_topic.security_alerts.arn]
  treat_missing_data  = "notBreaching"
}

# 8. SNS topic for alerts
resource "aws_sns_topic" "security_alerts" {
  name              = "cloudwatch-security-alerts"
  kms_master_key_id = aws_kms_key.sns.id

  tags = {
    Purpose = "Security Incident Notifications"
  }
}
